def fetch(timeout_s, cost_s):
    if cost_s > timeout_s:
        return "timeout"
    return "ok"

print(fetch(1.0, 0.5), "|", fetch(1.0, 2.0))

api = {1: {"items": ["a"], "next": 2}, 2: {"items": ["b", "c"], "next": None}}

def collect_all(api):
    out, page = [], 1
    while page is not None:
        block = api[page]
        out.extend(block["items"])
        page = block["next"]
    return out

print(collect_all(api))

def should_retry(status):
    return status in {429, 503}

for s in [400, 404, 429, 503, 200]:
