        "status_code": status,
        "cache_hit": cache_hit,
    }

print(min_provenance("https://api.example/x", 200, False))

def assert_keys(payload, required):
    missing = sorted(set(required) - set(payload))
    if missing:
        raise AssertionError(f"missing keys: {missing}")
    print("ok")

assert_keys({"lat": 1, "lon": 2}, ["lat", "lon"])
try:
    assert_keys({"lat": 1}, ["lat", "lon"])
except AssertionError as e:
    print(e)

def fetch_with_fallback(status, local_body):
    if status >= 500:
        return local_body, "offline"
    if status == 200:
        return {"online": True}, "online"
    return local_body, "offline"

print(fetch_with_fallback(200, {"local": 1}))
print(fetch_with_fallback(503, {"local": 1}))

